local http = require "resty.http"
local ngx = require "ngx"

-- Proxy HTTP requests
function proxy_request()
  -- Get target URL from request arguments
  local url = ngx.var.arg_url

  -- Use lua-resty-http to fetch content
  local httpc = http.new()
  local res, err = httpc:request_uri(url)

  if not res then
    ngx.status = 500
    ngx.say("Failed to proxy request: " .. err)
    return
  end

  -- Return proxied content
  ngx.header["Content-Type"] = res.headers["Content-Type"]
  ngx.print(res.body)
end